using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

/// <summary>
/// Shared helper to create in-memory SchoolContext instances for tests.
/// </summary>
internal static class TestHelpers
{
    public static SchoolContext CreateContext(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    public static SchoolContext CreateSeededContext(string? dbName = null)
    {
        var context = CreateContext(dbName);
        SeedData(context);
        return context;
    }

    public static void SeedData(SchoolContext context)
    {
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 100000m,
            StartDate = new DateTime(2020, 9, 1)
        };
        context.Departments.Add(dept);

        var instructor = new Instructor
        {
            ID = 1,
            LastName = "Smith",
            FirstMidName = "John",
            HireDate = new DateTime(2015, 1, 15),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
        };
        context.Instructors.Add(instructor);

        var courses = new[]
        {
            new Course { CourseID = 1001, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 1002, Title = "Physics", Credits = 4, DepartmentID = 1 },
            new Course { CourseID = 1003, Title = "Mathematics", Credits = 3, DepartmentID = 1 }
        };
        context.Courses.AddRange(courses);

        var students = new[]
        {
            new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2019, 9, 1) },
            new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { ID = 3, LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { ID = 4, LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { ID = 5, LastName = "Li", FirstMidName = "Yan", EnrollmentDate = new DateTime(2021, 9, 1) }
        };
        context.Students.AddRange(students);

        var enrollments = new[]
        {
            new Enrollment { EnrollmentID = 1, CourseID = 1001, StudentID = 1, Grade = Grade.A },
            new Enrollment { EnrollmentID = 2, CourseID = 1002, StudentID = 1, Grade = Grade.B },
            new Enrollment { EnrollmentID = 3, CourseID = 1001, StudentID = 2, Grade = Grade.C }
        };
        context.Enrollments.AddRange(enrollments);

        context.SaveChanges();
    }
}

using ContosoUniversity;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    [DataRow(10, 1, 5, 2, DisplayName = "First page of two")]
    [DataRow(10, 2, 5, 2, DisplayName = "Second page of two")]
    [DataRow(3, 1, 10, 1, DisplayName = "Single page (fewer items than page size)")]
    [DataRow(0, 1, 10, 0, DisplayName = "Empty source")]
    public void Create_ReturnsCorrectTotalPages(int totalItems, int pageIndex, int pageSize, int expectedTotalPages)
    {
        // Arrange
        var source = Enumerable.Range(1, totalItems).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex, pageSize);

        // Assert
        Assert.AreEqual(expectedTotalPages, result.TotalPages);
        Assert.AreEqual(pageIndex, result.PageIndex);
    }

    [TestMethod]
    public void Create_FirstPage_ContainsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 12).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        CollectionAssert.AreEqual(new[] { 1, 2, 3, 4, 5 }, result);
    }

    [TestMethod]
    public void Create_LastPage_ContainsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 12).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 5);

        // Assert
        Assert.AreEqual(2, result.Count);
        CollectionAssert.AreEqual(new[] { 11, 12 }, result);
    }

    [TestMethod]
    [DataRow(1, false, DisplayName = "First page has no previous")]
    [DataRow(2, true, DisplayName = "Second page has previous")]
    public void HasPreviousPage_ReturnsExpected(int pageIndex, bool expected)
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex, 5);

        // Assert
        Assert.AreEqual(expected, result.HasPreviousPage);
    }

    [TestMethod]
    [DataRow(4, false, DisplayName = "Last page has no next")]
    [DataRow(1, true, DisplayName = "First page has next")]
    public void HasNextPage_ReturnsExpected(int pageIndex, bool expected)
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex, 5);

        // Assert
        Assert.AreEqual(expected, result.HasNextPage);
    }

    [TestMethod]
    public void Constructor_SetsPropertiesCorrectly()
    {
        // Arrange & Act
        var list = new PaginatedList<string>(new List<string> { "a", "b" }, 10, 2, 5);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
        Assert.AreEqual(2, list.TotalPages);
        Assert.AreEqual(2, list.Count);
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain any stale messages from prior tests (static queue)
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "New Student 'Alice Smith' has been created")]
    [DataRow(EntityOperation.UPDATE, "Student 'Alice Smith' has been updated")]
    [DataRow(EntityOperation.DELETE, "Student 'Alice Smith' has been deleted")]
    public void SendNotification_WithDisplayName_GeneratesCorrectMessage(EntityOperation operation, string expectedMessage)
    {
        // Act
        _sut.SendNotification("Student", "1", "Alice Smith", operation, "Admin");
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual(expectedMessage, notification.Message);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual(operation.ToString(), notification.Operation);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Course", "42", EntityOperation.CREATE);
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Course (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.UPDATE);
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_WhenEmpty_ReturnsNull()
    {
        // Act
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(notification);
    }

    [TestMethod]
    public void SendAndReceive_MultiplNotifications_AreOrderedFIFO()
    {
        // Arrange
        _sut.SendNotification("A", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
        _sut.SendNotification("C", "3", "Third", EntityOperation.DELETE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.AreEqual("A", first!.EntityType);

        var second = _sut.ReceiveNotification();
        Assert.AreEqual("B", second!.EntityType);

        var third = _sut.ReceiveNotification();
        Assert.AreEqual("C", third!.EntityType);

        Assert.IsNull(_sut.ReceiveNotification());
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var before = DateTime.Now.AddSeconds(-1);

        // Act
        _sut.SendNotification("Test", "1", EntityOperation.CREATE);
        var notification = _sut.ReceiveNotification();
        var after = DateTime.Now.AddSeconds(1);

        // Assert
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation, but should not throw
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_CanBeCalledMultipleTimes()
    {
        // Should not throw
        _sut.Dispose();
        _sut.Dispose();
    }
}

