using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain any stale messages from prior tests (static queue)
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "New Student 'Alice Smith' has been created")]
    [DataRow(EntityOperation.UPDATE, "Student 'Alice Smith' has been updated")]
    [DataRow(EntityOperation.DELETE, "Student 'Alice Smith' has been deleted")]
    public void SendNotification_WithDisplayName_GeneratesCorrectMessage(EntityOperation operation, string expectedMessage)
    {
        // Act
        _sut.SendNotification("Student", "1", "Alice Smith", operation, "Admin");
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual(expectedMessage, notification.Message);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual(operation.ToString(), notification.Operation);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Course", "42", EntityOperation.CREATE);
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Course (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.UPDATE);
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_WhenEmpty_ReturnsNull()
    {
        // Act
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(notification);
    }

    [TestMethod]
    public void SendAndReceive_MultiplNotifications_AreOrderedFIFO()
    {
        // Arrange
        _sut.SendNotification("A", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
        _sut.SendNotification("C", "3", "Third", EntityOperation.DELETE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.AreEqual("A", first!.EntityType);

        var second = _sut.ReceiveNotification();
        Assert.AreEqual("B", second!.EntityType);

        var third = _sut.ReceiveNotification();
        Assert.AreEqual("C", third!.EntityType);

        Assert.IsNull(_sut.ReceiveNotification());
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var before = DateTime.Now.AddSeconds(-1);

        // Act
        _sut.SendNotification("Test", "1", EntityOperation.CREATE);
        var notification = _sut.ReceiveNotification();
        var after = DateTime.Now.AddSeconds(1);

        // Assert
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation, but should not throw
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_CanBeCalledMultipleTimes()
    {
        // Should not throw
        _sut.Dispose();
        _sut.Dispose();
    }
}

