using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateSeededContext();
        _controller = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    #region Index

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithAllStudents()
    {
        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(5, model.Count);
    }

    [TestMethod]
    public void Index_SearchString_FiltersStudents()
    {
        // Act
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersCorrectly()
    {
        // Act
        var result = _controller.Index(null, null, "Yan", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Li", model[0].LastName);
    }

    [TestMethod]
    [DataRow("name_desc", "Li", DisplayName = "Sort by name descending - first is Li")]
    [DataRow("Date", "Alexander", DisplayName = "Sort by date ascending - first is Alexander")]
    [DataRow("date_desc", "Barzdukas", DisplayName = "Sort by date descending - first is Barzdukas")]
    [DataRow("", "Alexander", DisplayName = "Default sort - first is Alexander")]
    public void Index_SortOrder_SortsCorrectly(string sortOrder, string expectedFirstLastName)
    {
        // Act
        var result = _controller.Index(sortOrder, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(expectedFirstLastName, model[0].LastName);
    }

    [TestMethod]
    public void Index_NewSearchString_ResetsPageToOne()
    {
        // Act
        var result = _controller.Index(null, null, "Al", 3) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // page is reset to 1 when searchString is provided
