using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateSeededContext();
        _controller = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    #region Index

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithAllStudents()
    {
        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(5, model.Count);
    }

    [TestMethod]
    public void Index_SearchString_FiltersStudents()
    {
        // Act
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersCorrectly()
    {
        // Act
        var result = _controller.Index(null, null, "Yan", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Li", model[0].LastName);
    }

    [TestMethod]
    [DataRow("name_desc", "Li", DisplayName = "Sort by name descending - first is Li")]
    [DataRow("Date", "Alexander", DisplayName = "Sort by date ascending - first is Alexander")]
    [DataRow("date_desc", "Barzdukas", DisplayName = "Sort by date descending - first is Barzdukas")]
    [DataRow("", "Alexander", DisplayName = "Default sort - first is Alexander")]
    public void Index_SortOrder_SortsCorrectly(string sortOrder, string expectedFirstLastName)
    {
        // Act
        var result = _controller.Index(sortOrder, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(expectedFirstLastName, model[0].LastName);
    }

    [TestMethod]
    public void Index_NewSearchString_ResetsPageToOne()
    {
        // Act
        var result = _controller.Index(null, null, "Al", 3) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // page is reset to 1 when searchString is provided
        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        // Act - null searchString should fall back to currentFilter
        var result = _controller.Index(null, "Li", null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
    }

    #endregion

    #region Details

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        // Act
        var result = _controller.Details(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual("Alexander", student.LastName);
    }

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    #endregion

    #region Create

    [TestMethod]
    public void Create_Get_ReturnsViewWithStudentDefaultDate()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual(DateTime.Today, student.EnrollmentDate);
    }

    [TestMethod]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = new Student
        {
            LastName = "TestStudent",
            FirstMidName = "New",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Act
        var result = _controller.Create(student) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(6, _context.Students.Count());
    }

    [TestMethod]
    public void Create_Post_MinValueDate_ReturnsViewWithModelError()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Bad",
            FirstMidName = "Date",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsFalse(_controller.ModelState.IsValid);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_DateBelow1753_ReturnsViewWithModelError()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Bad",
            FirstMidName = "Date",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    #endregion

    #region Edit

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        // Act
        var result = _controller.Edit(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual("Alexander", student.LastName);
    }

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = _context.Students.Find(1)!;
        _context.Entry(student).State = EntityState.Detached;

        var updatedStudent = new Student
        {
            ID = 1,
            LastName = "UpdatedName",
            FirstMidName = "Carson",
            EnrollmentDate = new DateTime(2019, 9, 1)
        };

        // Act
        var result = _controller.Edit(updatedStudent) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_MinValueDate_ReturnsViewWithError()
    {
        // Arrange
        var student = new Student
        {
            ID = 1,
            LastName = "Test",
            FirstMidName = "Test",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = _controller.Edit(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    #endregion

    #region Delete

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithStudent()
    {
        // Act
        var result = _controller.Delete(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual("Alexander", student.LastName);
    }

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
    {
        // Act
        var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(4, _context.Students.Count());
    }

    #endregion
}

