    public void Create_Post_ValidCourse_NoFile_RedirectsToIndex()
    {
        // Arrange
        var course = new Course
        {
            CourseID = 2001,
            Title = "Biology",
            Credits = 3,
            DepartmentID = 1
        };

        // Act
        var result = _controller.Create(course, null!) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(4, _context.Courses.Count());
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 3001 };

        // Act
        var result = _controller.Create(course, null!) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
    {
        // Arrange
        var course = new Course { CourseID = 2002, Title = "Art", Credits = 2, DepartmentID = 1 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.exe");
        fileMock.Setup(f => f.Length).Returns(1024);

        // Act
        var result = _controller.Create(course, fileMock.Object) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [TestMethod]
    public void Create_Post_FileTooLarge_ReturnsViewWithError()
    {
        // Arrange
        var course = new Course { CourseID = 2003, Title = "Music", Credits = 2, DepartmentID = 1 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("large.jpg");
        fileMock.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB

        // Act
        var result = _controller.Create(course, fileMock.Object) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

