namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context = null!;
    private InstructorsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateSeededContext();

        // Add a course assignment for the instructor
        _context.CourseAssignments.Add(new CourseAssignment { InstructorID = 1, CourseID = 1001 });
        _context.SaveChanges();

        _controller = new InstructorsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    #region Index

