using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context = null!;
    private NotificationsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateContext();
        _controller = new NotificationsController(_context);
        // Drain the static queue
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
        svc.Dispose();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void GetNotifications_WhenEmpty_ReturnsSuccessWithZeroCount()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value as dynamic;
        Assert.IsNotNull(json);
    }

    [TestMethod]
    public void GetNotifications_WithMessages_ReturnsNotifications()
    {
        // Arrange - enqueue some notifications
        var svc = new NotificationService();
        svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");
        svc.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE, "Admin");
        svc.Dispose();

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void GetNotifications_LimitsToTenNotifications()
    {
        // Arrange - enqueue more than 10 notifications
        var svc = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            svc.SendNotification("Test", i.ToString(), $"Item {i}", EntityOperation.CREATE);
        }
        svc.Dispose();

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
    }
}

