using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class ModelTests
{
    #region Person / Student / Instructor

    [TestMethod]
    public void Person_FullName_ReturnsLastNameCommaFirstName()
    {
        // Arrange
        var student = new Student { LastName = "Smith", FirstMidName = "John" };

        // Act & Assert
        Assert.AreEqual("Smith, John", student.FullName);
    }

    [TestMethod]
    [DataRow("Doe", "Jane", "Doe, Jane")]
    [DataRow("O'Brien", "Conan", "O'Brien, Conan")]
    [DataRow("", "", ", ")]
    public void Person_FullName_VariousInputs(string lastName, string firstName, string expected)
    {
        // Arrange
        var instructor = new Instructor { LastName = lastName, FirstMidName = firstName };

        // Act & Assert
        Assert.AreEqual(expected, instructor.FullName);
    }

    [TestMethod]
    public void Student_InheritsFromPerson()
    {
        // Arrange & Act
        var student = new Student
        {
            ID = 1,
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = DateTime.Now
        };

        // Assert
        Assert.IsInstanceOfType<Person>(student);
    }

    [TestMethod]
    public void Instructor_InheritsFromPerson()
    {
        // Arrange & Act
        var instructor = new Instructor
        {
            ID = 1,
            LastName = "Test",
            FirstMidName = "Instructor",
            HireDate = DateTime.Now
        };

        // Assert
        Assert.IsInstanceOfType<Person>(instructor);
    }

    #endregion

    #region Course

    [TestMethod]
    public void Course_PropertiesSetCorrectly()
    {
        // Arrange & Act
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/uploads/test.jpg"
        };

        // Assert
        Assert.AreEqual(1050, course.CourseID);
        Assert.AreEqual("Chemistry", course.Title);
        Assert.AreEqual(3, course.Credits);
        Assert.AreEqual(1, course.DepartmentID);
        Assert.AreEqual("/uploads/test.jpg", course.TeachingMaterialImagePath);
    }

    #endregion

    #region Enrollment

    [TestMethod]
    [DataRow(Grade.A)]
    [DataRow(Grade.B)]
    [DataRow(Grade.C)]
    [DataRow(Grade.D)]
    [DataRow(Grade.F)]
    public void Enrollment_GradeValues_AreValid(Grade grade)
    {
        // Arrange & Act
        var enrollment = new Enrollment
        {
            EnrollmentID = 1,
            CourseID = 100,
            StudentID = 1,
            Grade = grade
        };

        // Assert
        Assert.AreEqual(grade, enrollment.Grade);
    }

    [TestMethod]
    public void Enrollment_NullGrade_IsValid()
    {
        // Arrange & Act
        var enrollment = new Enrollment
        {
            EnrollmentID = 1,
            CourseID = 100,
            StudentID = 1,
            Grade = null
        };

        // Assert
        Assert.IsNull(enrollment.Grade);
    }

    #endregion

    #region Department

    [TestMethod]
    public void Department_PropertiesSetCorrectly()
    {
        // Arrange & Act
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000m,
            StartDate = new DateTime(2020, 9, 1),
            InstructorID = 5
        };

        // Assert
        Assert.AreEqual(1, dept.DepartmentID);
        Assert.AreEqual("Engineering", dept.Name);
        Assert.AreEqual(350000m, dept.Budget);
        Assert.AreEqual(5, dept.InstructorID);
    }

    [TestMethod]
    public void Department_NullableInstructorID_CanBeNull()
    {
        // Arrange & Act
        var dept = new Department { Name = "Science" };

        // Assert
        Assert.IsNull(dept.InstructorID);
    }

    #endregion

    #region Notification

    [TestMethod]
    public void Notification_PropertiesSetCorrectly()
    {
        // Arrange & Act
        var now = DateTime.Now;
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Student",
            EntityId = "42",
            Operation = "CREATE",
            Message = "New Student has been created",
            CreatedAt = now,
            CreatedBy = "Admin",
            IsRead = false
        };

        // Assert
        Assert.AreEqual(1, notification.Id);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual(now, notification.CreatedAt);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsNull(notification.ReadAt);
    }

    [TestMethod]
    public void EntityOperation_HasExpectedValues()
    {
        // Assert
        Assert.AreEqual(0, (int)EntityOperation.CREATE);
        Assert.AreEqual(1, (int)EntityOperation.UPDATE);
        Assert.AreEqual(2, (int)EntityOperation.DELETE);
    }

    #endregion

    #region CourseAssignment

    [TestMethod]
    public void CourseAssignment_PropertiesSetCorrectly()
    {
        // Arrange & Act
        var assignment = new CourseAssignment
        {
            InstructorID = 1,
            CourseID = 1001
        };

        // Assert
        Assert.AreEqual(1, assignment.InstructorID);
        Assert.AreEqual(1001, assignment.CourseID);
    }

    #endregion

    #region OfficeAssignment

    [TestMethod]
    public void OfficeAssignment_PropertiesSetCorrectly()
    {
        // Arrange & Act
        var office = new OfficeAssignment
        {
            InstructorID = 1,
            Location = "Room 201"
        };

        // Assert
        Assert.AreEqual(1, office.InstructorID);
        Assert.AreEqual("Room 201", office.Location);
    }

    #endregion
}

